#!/usr/bin/env dotnet
#:include *.cs
#:include Models/*.cs
#:exclude Scratch.cs

var person = new Person("Ada", "Lovelace");
Console.WriteLine(Formatter.FullNameUpper(person));

static class Formatter
{
    public static string FullNameUpper(Person p) =>
        $"{p.FirstName} {p.LastName}".ToUpperInvariant();
}

